components.openAPISpec:
openapi: 3.0.3
info:
  title: Todo API
  version: 1.0.0
servers:
  - url: /api/v1
paths:
  /health:
    get:
      responses:
        '200': {description: OK}
  /auth/register:
    post:
      requestBody:
        required: true
        content:
          application/json:
            schema:
              type: object
              required: [email, password]
              properties:
                email: {type: string, format: email}
                password: {type: string}
      responses:
        '201': {description: Created}
        '400': {description: Validation error}
  /auth/login:
    post:
      requestBody:
        required: true
        content:
          application/json:
            schema:
              type: object
              required: [email, password]
              properties:
                email: {type: string}
                password: {type: string}
      responses:
        '200': {description: OK, sets session cookie}
        '401': {description: Invalid credentials}
        '423': {description: Account locked}
  /auth/logout:
    post:
      responses:
        '204': {description: Logged out}
  /auth/password-reset/request:
    post:
      requestBody:
        required: true
        content:
          application/json:
            schema:
              type: object
              properties:
                email: {type: string}
      responses:
        '202': {description: Email sent}
  /auth/password-reset/confirm:
    post:
      requestBody:
        required: true
        content:
          application/json:
            schema:
              type: object
              properties:
                token: {type: string}
                password: {type: string}
      responses:
        '200': {description: Updated}
  /todos:
    get:
      parameters:
        - {name: completed, in: query, schema: {type: boolean}}
        - {name: categoryId, in: query, schema: {type: string}}
        - {name: dueFrom, in: query, schema: {type: string, format: date-time}}
        - {name: dueTo, in: query, schema: {type: string, format: date-time}}
      responses:
        '200':
          description: List of todos
          content:
            application/json:
              schema: {type: array, items: {$ref: '#/components/schemas/Todo'}}
    post:
      requestBody:
        required: true
        content:
          application/json:
            schema: {$ref: '#/components/schemas/TodoInput'}
      responses:
        '201': {description: Created}
        '400': {description: Validation error}
  /todos/{id}:
    get:
      parameters: [{name: id, in: path, required: true, schema: {type: string}}]
      responses:
        '200': {description: OK}
        '404': {description: Not found}
    put:
      parameters: [{name: id, in: path, required: true, schema: {type: string}}]
      requestBody:
        required: true
        content:
          application/json:
            schema: {$ref: '#/components/schemas/TodoInput'}
      responses:
        '200': {description: Updated}
        '409': {description: Version conflict}
    delete:
      parameters: [{name: id, in: path, required: true, schema: {type: string}}]
      responses:
        '204': {description: Deleted}
  /categories:
    get:
      responses:
        '200': {description: OK}
    post:
      requestBody:
        required: true
        content:
          application/json:
            schema:
              type: object
              properties:
                name: {type: string, maxLength: 50}
      responses:
        '201': {description: Created}
        '409': {description: Duplicate name}
  /categories/{id}:
    put:
      parameters: [{name: id, in: path, required: true, schema: {type: string}}]
      requestBody:
        required: true
        content:
          application/json:
            schema:
              type: object
              properties:
                name: {type: string}
      responses:
        '200': {description: Updated}
    delete:
      parameters: [{name: id, in: path, required: true, schema: {type: string}}]
      responses:
        '204': {description: Deleted, todos unassigned}
components:
  schemas:
    Todo:
      type: object
      properties:
        id: {type: string}
        title: {type: string, maxLength: 200}
        description: {type: string, maxLength: 2000}
        dueDate: {type: string, format: date-time}
        categoryId: {type: string, nullable: true}
        completed: {type: boolean}
        completedAt: {type: string, format: date-time, nullable: true}
        version: {type: integer}
        createdAt: {type: string, format: date-time}
    TodoInput:
      type: object
      required: [title]
      properties:
        title: {type: string, maxLength: 200}
        description: {type: string, maxLength: 2000}
        dueDate: {type: string, format: date-time}
        categoryId: {type: string, nullable: true}
        completed: {type: boolean}
        version: {type: integer}
